<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;
class Invoice extends Model{protected $fillable=['tenant_id','purchase_order_id','supplier_id','invoice_number','status','currency','subtotal','tax_amount','total_amount','issued_at','due_at','original_name','storage_path','disk','mime_type','size_bytes','match_status','match_details','control_comment','controlled_by','controlled_at','payment_reference','payment_transmitted_at','paid_at'];protected $hidden=['storage_path','disk'];protected function casts():array{return['subtotal'=>'integer','tax_amount'=>'integer','total_amount'=>'integer','size_bytes'=>'integer','issued_at'=>'date','due_at'=>'date','match_details'=>'array','controlled_at'=>'datetime','payment_transmitted_at'=>'datetime','paid_at'=>'datetime'];}public function purchaseOrder():BelongsTo{return $this->belongsTo(PurchaseOrder::class);}public function supplier():BelongsTo{return $this->belongsTo(Supplier::class);}public function controller():BelongsTo{return $this->belongsTo(User::class,'controlled_by');}}
